import type { Ticket, TicketPayload, TicketPriority, TicketStatus } from "../lib/types";

type TicketFormProps = {
  mode: "create" | "edit";
  ticket?: Ticket;
};

type ValidationErrors = Partial<Record<keyof TicketPayload, string>>;

const statusOptions: TicketStatus[] = ["todo", "doing", "done"];
const priorityOptions: TicketPriority[] = ["low", "medium", "high"];

export function TicketForm({ mode, ticket }: TicketFormProps) {
  const router = useRouter();
  const [form, setForm] = useState<TicketPayload>({
    title: ticket?.title ?? "",
    description: ticket?.description ?? "",
    status: ticket?.status ?? "todo",
    priority: ticket?.priority ?? "medium",
    due_date: ticket?.due_date ?? "",
  });
  const [errors, setErrors] = useState<ValidationErrors>({});
  const [submitError, setSubmitError] = useState("");
  const [loading, setLoading] = useState(false);

  const title = useMemo(
    () => (mode === "create" ? "チケットを作成" : `チケット #${ticket?.id} を編集`),
    [mode, ticket?.id],
  );

  function validate(nextForm: TicketPayload): ValidationErrors {
    const nextErrors: ValidationErrors = {};
    if (!nextForm.title.trim()) {
      nextErrors.title = "タイトルは必須です。";
    } else if (nextForm.title.trim().length > 100) {
      nextErrors.title = "タイトルは100文字以内で入力してください。";
    }

    if (nextForm.description.length > 1000) {
      nextErrors.description = "説明は1000文字以内で入力してください。";
    }

    if (nextForm.due_date && Number.isNaN(Date.parse(nextForm.due_date))) {
      nextErrors.due_date = "期限日は正しい日付形式で入力してください。";
    }
    return nextErrors;
  }

  async function handleSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    const nextErrors = validate(form);
    setErrors(nextErrors);
    setSubmitError("");
    if (Object.keys(nextErrors).length > 0) {
      return;
    }

    setLoading(true);
    try {
      if (mode === "create") {
        await createTicket(form);
      } else if (ticket) {
        await updateTicket(ticket.id, form);
      }
      router.push("/");
      router.refresh();
    } catch (caught) {
      setSubmitError(caught instanceof Error ? caught.message : "保存に失敗しました。");
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="page-shell">
      <div className="container">
        <div className="card form-card stack">
          <div className="row space-between">
            <div className="stack" style={{ gap: 6 }}>
              <h1 style={{ margin: 0 }}>{title}</h1>
              <p className="subtitle">
                必須項目と入力制約を画面側でも先に検証し、失敗時は理由をそのまま表示します。
              </p>
            </div>
            <Link className="button secondary" href="/">
              一覧へ戻る
            </Link>
          </div>
          <form className="stack" onSubmit={handleSubmit}>
            <div className="field">
              <label className="label" htmlFor="title">
                タイトル
              </label>
              <input
                id="title"
                className="input"
                value={form.title}
                onChange={(event) => setForm((current) => ({ ...current, title: event.target.value }))}
                maxLength={100}
                required
              />
              {errors.title ? <div className="alert error">{errors.title}</div> : null}
            </div>
            <div className="field">
              <label className="label" htmlFor="description">
                説明
              </label>
              <textarea
                id="description"
                className="textarea"
                value={form.description}
                onChange={(event) =>
                  setForm((current) => ({ ...current, description: event.target.value }))
                }
                maxLength={1000}
              />
              {errors.description ? <div className="alert error">{errors.description}</div> : null}
            </div>
            <div className="row">
              <div className="field" style={{ flex: 1 }}>
                <label className="label" htmlFor="status">
                  ステータス
                </label>
                <select
                  id="status"
                  className="select"
                  value={form.status}
                  onChange={(event) =>
                    setForm((current) => ({
                      ...current,
                      status: event.target.value as TicketStatus,
                    }))
                  }
                >
                  {statusOptions.map((option) => (
                    <option key={option} value={option}>
                      {option}
                    </option>
                  ))}
                </select>
              </div>
              <div className="field" style={{ flex: 1 }}>
                <label className="label" htmlFor="priority">
                  優先度
                </label>
                <select
