          {loading ? <div className="alert info">チケットを読み込み中です。</div> : null}

          {ticket ? (
            <div className="stack">
              <div className="row">
                <span className={`pill ${ticket.status}`}>{ticket.status}</span>
                <span className="pill">{ticket.priority}</span>
                <span className="pill">期限日: {ticket.due_date || "未設定"}</span>
              </div>
              <div className="card" style={{ padding: 20 }}>
                <h2 style={{ marginTop: 0 }}>説明</h2>
                <p style={{ margin: 0, whiteSpace: "pre-wrap" }}>
                  {ticket.description || "説明はありません。"}
                </p>
              </div>
              <div className="row">
                <span className="subtitle">
                  作成日時: {new Date(ticket.created_at).toLocaleString("ja-JP")}
                </span>
                <span className="subtitle">
                  更新日時: {new Date(ticket.updated_at).toLocaleString("ja-JP")}
                </span>
              </div>
            </div>
          ) : null}
        </div>
      </div>
    </div>
  );
}

